import{_ as a,o as i,c as t,a2 as s}from"./chunks/framework.BKG_UbFK.js";const g=JSON.parse('{"title":"Migrating from an existing Spatie install","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/migration.md","filePath":"en/guide/migration.md"}'),o={name:"en/guide/migration.md"};function n(l,e,d,r,c,h){return i(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="migrating-from-an-existing-spatie-install" tabindex="-1">Migrating from an existing Spatie install <a class="header-anchor" href="#migrating-from-an-existing-spatie-install" aria-label="Permalink to &quot;Migrating from an existing Spatie install&quot;">​</a></h1><p>If your application already uses <code>spatie/laravel-permission</code> with existing roles, permissions, and assignments, <code>clearance:install</code> detects and preserves them - it never runs Spatie&#39;s migrations if the <code>roles</code> table already exists. See <a href="/clearance-docs/en/guide/installation.html">Installation</a> for the full install flow.</p><p>Once installed, use <code>clearance:backfill</code> to adopt Clearance&#39;s own metadata onto your existing roles and guards.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:backfill</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # meta + role scope + guards</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:backfill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --only=meta</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # just one section</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:backfill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dry-run</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # preview, no writes</span></span></code></pre></div><h2 id="what-each-section-does" tabindex="-1">What each section does <a class="header-anchor" href="#what-each-section-does" aria-label="Permalink to &quot;What each section does&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Section</th><th>Effect</th></tr></thead><tbody><tr><td><code>meta</code></td><td>Seeds a <code>clr_meta</code> display name (title-cased role name) for every role without one.</td></tr><tr><td><code>roles</code></td><td>Seeds <code>clr_role_meta</code> defaults (<code>scope=global</code>, <code>is_locked=false</code>) for every role without one.</td></tr><tr><td><code>guards</code></td><td>Imports guards from <code>config(&#39;auth.guards&#39;)</code> into <code>clr_guards</code>, filtered by <code>allowed_guard_drivers</code>.</td></tr></tbody></table><p>Use <code>--only=&lt;section&gt;</code> to run a single section instead of all three.</p><div class="tip custom-block"><p class="custom-block-title">Idempotent</p><p>All sections are idempotent - re-running <code>clearance:backfill</code> is safe and won&#39;t duplicate or overwrite existing <code>clr_*</code> rows.</p></div><h2 id="edge-cases" tabindex="-1">Edge cases <a class="header-anchor" href="#edge-cases" aria-label="Permalink to &quot;Edge cases&quot;">​</a></h2><p>The package repository has a deeper migration guide covering edge cases not summarized here - notably what happens when your database already has a role named <code>super_admin</code> (or an alias like <code>superadmin</code>, <code>root</code>, <code>owner</code>) that collides with Clearance&#39;s own <code>super_admin</code> role, and notes on custom <code>Role</code>/<code>Permission</code> model subclasses and guard import behavior. Read it before backfilling a production database with non-trivial existing role data. See also <a href="/clearance-docs/en/features/super-admin.html">Super Admin</a> for alias detection behavior during <code>clearance:install</code>.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/clearance-docs/en/guide/installation.html">Installation</a> - the full <code>clearance:install</code> flow</li><li><a href="/clearance-docs/en/api/artisan-commands.html">Artisan commands</a> - full command reference</li><li><a href="/clearance-docs/en/guide/architecture.html">Architecture</a> - the <code>clr_*</code> tables that backfill populates</li></ul>`,12)])])}const m=a(o,[["render",n]]);export{g as __pageData,m as default};
